use crate::api::*;
use std::sync::RwLock;

pub struct VectorDB {
    data: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        self.data.write().unwrap().push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let len = vectors.len();
        self.data.write().unwrap().extend(vectors);
        len
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let top_k = top_k as usize;
        let data = self.data.read().unwrap();
        let mut results: Vec<SearchResult> = data.iter().map(|(id, v)| {
            SearchResult {
                id: *id,
                distance: crate::distance::l2_distance(vector, v),
            }
        }).collect();

        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results.truncate(top_k);
        results
    }
}

use std::arch::x86_64::*;

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    assert_eq!(a.len(), 128);
    assert_eq!(b.len(), 128);

    unsafe {
        let mut sum = _mm512_setzero_ps();
        for i in (0..128).step_by(16) {
            let va = _mm512_loadu_ps(a.as_ptr().add(i));
            let vb = _mm512_loadu_ps(b.as_ptr().add(i));
            let diff = _mm512_sub_ps(va, vb);
            let sq = _mm512_mul_ps(diff, diff);
            sum = _mm512_add_ps(sum, sq);
        }
        (_mm512_reduce_add_ps(sum) as f64)
    }
}

