        let d3 = _mm512_sub_ps(va3, vb3);
        sum3 = _mm512_fmadd_ps(d3, d3, sum3);
    }

    let s01 = _mm512_add_ps(sum0, sum1);
    let s23 = _mm512_add_ps(sum2, sum3);
    let st = _mm512_add_ps(s01, s23);

    _mm512_reduce_add_ps(st) as f64
